import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import { useLocale } from '@/hooks/useLocale';
import SectionTitle from '@/components/atoms/SectionTitle';
import AccentText from '@/components/atoms/AccentText';
import TechStackContainer from '../molecules/TechStackContainer';

const HelloSection = () => {
  const { t, language } = useLocale();
  const [containerRef, isContainerInView] = useInView({
    triggerOnce: false,
    threshold: 0.1
  });

  const [contentRef, isContentInView] = useInView({
    triggerOnce: false,
    threshold: 0.1
  });

  const [skillsRef, isSkillsInView] = useInView({
    triggerOnce: false,
    threshold: 0.1
  });

  return (
    <div className="relative w-full bg-white dark:bg-[#0f0f0f] px-6 sm:px-8 lg:px-11 transition-colors duration-300">
      <div className="w-full flex flex-col items-center py-20">
        {/* Section label */}
        <div className="mb-8 lg:mb-12 text-center">
          <SectionTitle text="hello" />
        </div>

        <motion.div
          ref={containerRef}
          className="content-container"
          initial={{ opacity: 0, y: 20 }}
          animate={isContainerInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
          transition={{ duration: 0.6 }}
        >
          {/* Text Content Container */}
          <motion.div
            ref={contentRef}
            className="flex flex-col gap-6 lg:gap-8 text-center mx-auto max-w-2xl w-full"
            initial={{ opacity: 0, x: 80 }}
            animate={isContentInView ? { opacity: 1, x: 0 } : { opacity: 0, x: 50 }}
            transition={{ duration: 0.8, delay: 0.4 }}
          >
            {/* About Text */}
            <div className="flex flex-col gap-4 mt-0">
              <motion.h3
                className="
                  font-sans font-normal
                  text-gray-800 dark:text-gray-200
                  tracking-normal
                  text-pretty
                  leading-snug
                  whitespace-pre-wrap
                "
                style={{ fontSize: 'clamp(1.25rem, 4.5vw, 1.875rem)' }}
                initial={{ opacity: 0 }}
                animate={isContentInView ? { opacity: 1 } : { opacity: 0 }}
                transition={{ duration: 0.6, delay: 0.6 }}
              >
                {language === 'en' ? (
                  <>
                    Hi, I'm <AccentText>Yurim Lee</AccentText>,<br />
                    A Frontend Developer with 5 years of experience in the<br />
                    <AccentText>JavaScript</AccentText> and <AccentText>TypeScript</AccentText> ecosystem.
                  </>
                ) : (
                  <>
                    <AccentText>안녕하세요</AccentText>,<br />
                    JavaScript와 TypeScript 생태계에서 <br />
                    5년째 제품을 만들고 있는 <AccentText>이유림</AccentText>입니다.
                  </>
                )}
              </motion.h3>

              <motion.div
                className="flex flex-col gap-3 sm:gap-4 w-full"
                initial={{ opacity: 0, x: 50 }}
                animate={isContentInView ? { opacity: 1, x: 0 } : { opacity: 0, x: 50 }}
                transition={{ duration: 0.6, delay: 0.8 }}
              >
                {t('about.description').split('\n\n').map((para, i) => (
                  <p
                    key={i}
                    className="
                      font-sans font-light
                      text-gray-600 dark:text-gray-400
                      tracking-normal
                      leading-relaxed
                      text-center
                      whitespace-pre-wrap
                    "
                    style={{ fontSize: 'clamp(0.875rem, 3vw, 1.25rem)' }}
                  >
                    {para}
                  </p>
                ))}
              </motion.div>
            </div>

            {/* Skills Section */}
            <motion.div
              ref={skillsRef}
              className="flex flex-col gap-4 mt-4 lg:mt-8 items-center"
              initial={{ opacity: 0 }}
              animate={isSkillsInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 50 }}
              transition={{ duration: 0.6, delay: 1 }}
            >
              <SectionTitle text="skills" />
              <div className="flex justify-center w-full">
                <TechStackContainer />
              </div>
            </motion.div>
          </motion.div>
        </motion.div>
      </div>
    </div>
  );
};

export default HelloSection;
